# Shape entity implementations - structs and classes

from shapes_core import IShape, ShapeType

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

class Circle(IShape):
    center: Point
    radius: float

    def __init__(self, center: Point, radius: float):
        self.center = center
        self.radius = radius

    @virtual
    def area(self) -> float:
        pi: float = 3.14159
        return pi * self.radius * self.radius

    @virtual
    def perimeter(self) -> float:
        pi: float = 3.14159
        return 2.0 * pi * self.radius

    @virtual
    def get_shape_type(self) -> ShapeType:
        return ShapeType.CIRCLE

class Rectangle(IShape):
    top_left: Point
    width: float
    height: float

    def __init__(self, top_left: Point, width: float, height: float):
        self.top_left = top_left
        self.width = width
        self.height = height

    @virtual
    def area(self) -> float:
        return self.width * self.height

    @virtual
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @virtual
    def get_shape_type(self) -> ShapeType:
        return ShapeType.RECTANGLE

class ShapeGroup:
    shapes: list[IShape]

    def __init__(self):
        self.shapes = []

    def add(self, shape: IShape) -> None:
        self.shapes.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.shapes:
            total = total + shape.area()
        return total

    def count(self) -> int:
        return len(self.shapes)

    def get_first(self) -> IShape:
        return self.shapes[0]

