# Shape utilities - calculations and transformations

from shapes_core import ShapeType
from shapes_entities import Point, Circle, Rectangle

def distance(p1: Point, p2: Point) -> float:
    dx: float = p2.x - p1.x
    dy: float = p2.y - p1.y
    return (dx * dx + dy * dy) ** 0.5

def scale_circle(c: Circle, factor: float) -> Circle:
    new_radius: float = c.radius * factor
    return Circle(c.center, new_radius)

def rectangle_from_corners(p1: Point, p2: Point) -> Rectangle:
    width: float = abs(p2.x - p1.x)
    height: float = abs(p2.y - p1.y)
    return Rectangle(p1, width, height)

class ShapeStatistics:
    shape_count: int
    total_area_sum: float

    def __init__(self):
        self.shape_count = 0
        self.total_area_sum = 0.0

    def record_shape(self, shape: IShape) -> None:
        self.shape_count += 1
        self.total_area_sum += shape.area()

    def get_average_area(self) -> float:
        if self.shape_count == 0:
            return 0.0
        return self.total_area_sum / float(self.shape_count)
